// Extrai JSON da resposta do Claude
const resposta = $input.first().json.content[0].text;
const inicio = resposta.indexOf('{');
const fim = resposta.lastIndexOf('}') + 1;
const acao = JSON.parse(resposta.substring(inicio, fim));

// Adiciona contexto original
const contexto = $('WA_RECEPTOR').first().json;

return [{ json: { ...acao, remetente: contexto.remetente, timestamp: contexto.timestamp } }];
